scwin.chk_excelExport = function(GriddataBook) {
    var Grid = "";
    if (GriddataBook.GetCheckedRows(1) <= 0) {
        return;
    }
    Grid = GriddataBook.GetGridData("", "");
    for (var row = 1; row <= GriddataBook.getTotalRow(); row++) {
        if (GriddataBook.getCellData(row, 1) == "N") {
            GriddataBook.removeRow(row, false);
            row = row - 1;
        }
    }
    GriddataBook.ExcelExport();
    GriddataBook.SetGridData("", "", Grid);
};

