scwin.massDataSeparation = function() {
    //cmStMbName.Value = "C:\\KBCOMM\\COMMONDATA\\THKJIER01_KOR01B010000520091117_TKJIER01";
    var fso = new ActiveXObject("Scripting.FileSystemObject");
    if (!fso.FileExists(cmStMbName.getValue())) {
        $c.iz.data.alert("해당파일이 없습니다.", "파일에러");
        return -1;
    }
    var f = fso.OpenTextFile(cmStMbName.getValue(), 1);
    var tmp = "",
        massData = "";
    while (!f.AtEndOfStream) {
        tmp = f.ReadLine();
        if (tmp.substring(0, 4) == "THKJ") {
            var fso2 = new ActiveXObject("Scripting.FileSystemObject");
            var filename = "C:\\KBCOMM\\COMMONDATA\\" + tmp.substring(5);
            if (!fso2.FileExists(filename)) {
                fso2.CreateTextFile(filename, true);
            }
            var f2 = fso2.OpenTextFile(filename, 2);
            f2.Write(massData);
            f2.Close();
            fso2.Close;
            massData = "";
        } else massData += tmp + "\r\n";
    }
    f.Close();
    fso.Close;
};

