scwin.TAB1_OnItemChanged = function(info) {
    //여기에 구현코드를 삽입하세요.
    //20100831 전자전표판단규칙 수정 keh
    //if(TAB1.GetActivePage() == 1 || TAB1.GetActivePage() == 3 || TAB1.GetActivePage() == 5 || TAB1.GetActivePage() == 7 || TAB1.GetActivePage() == 9)

    //20100831 전자전표판단규칙 추가 keh
    if (TAB1.getSelectedTabIndex() == 1 || TAB1.getSelectedTabIndex() == 3 ||
        TAB1.getSelectedTabIndex() == 5 || TAB1.getSelectedTabIndex() == 7 ||
        TAB1.getSelectedTabIndex() == 9 || TAB1.getSelectedTabIndex() == 11 ||
        TAB1.getSelectedTabIndex() == 6 || TAB1.getSelectedTabIndex() == 10) //20140116_유재현 : 책임자승인규칙, 전자전표판단규칙 추가 (어플코드 필수)

    {
        if (prcssDstic.getValue() == "02") {
            uapplCd.setMandatory(true);
        }
        msgChnlDstcd.setMandatory(false);
        msgChnlDstcd.hide();
        Text_msgChnlDstcd.hide();
        msgChnlDstcd.setDisabled(true);
        msgChnlDstcd.clearValue();
    } else {
        uapplCd.setMandatory(false);
        msgChnlDstcd.setMandatory(false);
        if (TAB1.getSelectedTabIndex() == 0) {
            msgChnlDstcd.setMandatory(true);
            msgChnlDstcd.show('');
            Text_msgChnlDstcd.show('');
            msgChnlDstcd.setDisabled(false);
            msgChnlDstcd.setValue('01');
        } else {
            msgChnlDstcd.setMandatory(false);
            msgChnlDstcd.hide();
            Text_msgChnlDstcd.hide();
            msgChnlDstcd.setDisabled(true);
            msgChnlDstcd.clearValue();
        }
    }
};

